import React, { useState } from "react";
import { ArrowUpRight, ArrowDownLeft, Sun, Moon } from "lucide-react";
import { useCurrency } from "../context/CurrencyContext";
import DepositScreen from "./DepositScreen";
import ConfirmPaymentScreen from "./ConfirmPaymentScreen";
import PaymentProcessingScreen from "./PaymentProcessingScreen";

export default function HomeScreen({
  balance = 1500,
  savingsBalance = 0,
  transactions = [],
  userName,
  darkMode,
  toggleDarkMode,
}) {
  const currencyContext = useCurrency();
  const formatAmount = currencyContext?.formatAmount || ((amt) => `₦${amt.toLocaleString()}`);

  // ---------- STATE ----------
  const [mainBalance, setMainBalance] = useState(balance);
  const [showDepositFlow, setShowDepositFlow] = useState(false);
  const [depositStep, setDepositStep] = useState("DepositScreen"); // DepositScreen | ConfirmPaymentScreen | PaymentProcessingScreen
  const [depositAmount, setDepositAmount] = useState(0);
  const [depositSource, setDepositSource] = useState("Access Bank - **** 1234");

  // ---------- FLOW HANDLERS ----------
  const openDepositFlow = () => {
    setDepositStep("DepositScreen");
    setShowDepositFlow(true);
  };

  const handleDepositConfirm = (amount, source) => {
    setDepositAmount(amount);
    setDepositSource(source);
    setDepositStep("ConfirmPaymentScreen");
  };

  const handlePaymentProcessing = () => {
    setDepositStep("PaymentProcessingScreen");

    // After 3s, update balance and close flow
    setTimeout(() => {
      setMainBalance((prev) => prev + depositAmount);

      // Optionally, add to transactions here
      transactions.unshift({
        id: Date.now(),
        type: "deposit",
        title: "Deposit",
        amount: depositAmount,
        date: new Date().toLocaleDateString(),
      });

      setShowDepositFlow(false);
      setDepositAmount(0);
      setDepositSource("Access Bank - **** 1234");
    }, 3000);
  };

  // ---------- RENDER ----------
  return (
    <div
      className={`px-6 pb-32 min-h-screen animate-fade-in ${
        darkMode ? "bg-gray-900 text-gray-100" : "bg-gray-50 text-gray-900"
      }`}
    >
      {/* Greeting and Dark Mode Toggle */}
      <div className="flex justify-between items-center mb-6 pt-6">
        <h1 className="text-2xl font-bold">Hello, {userName} 👋</h1>
        <button onClick={toggleDarkMode}>
          {darkMode ? <Sun size={22} /> : <Moon size={22} />}
        </button>
      </div>

      {/* Total Balance Card */}
      <div
        className={`rounded-3xl p-6 mb-8 shadow-lg ${
          darkMode
            ? "bg-gray-800"
            : "bg-gradient-to-br from-emerald-600 to-teal-800 text-white"
        }`}
      >
        <div className="flex justify-between items-start mb-2">
          <span
            className={`text-sm font-medium ${
              darkMode ? "text-gray-400" : "text-emerald-100"
            }`}
          >
            Total Balance
          </span>
          <span className="text-lg font-bold">Nest.</span>
        </div>

        <div className="text-4xl font-bold mb-4 tracking-tight">
          {formatAmount(mainBalance)}
        </div>

        {/* Savings Balance */}
        <p
          className={`font-medium mb-4 ${
            darkMode ? "text-gray-300" : "text-emerald-200"
          }`}
        >
          Savings: {formatAmount(savingsBalance)}
        </p>

        {/* Deposit / Withdraw Buttons */}
        <div className="flex gap-3">
          <button
            onClick={openDepositFlow}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition-colors ${
              darkMode
                ? "bg-emerald-600/30 hover:bg-emerald-600/40 text-white"
                : "bg-emerald-500/20 hover:bg-emerald-500/30"
            }`}
          >
            <ArrowUpRight className="w-4 h-4" /> Deposit
          </button>

          <button
            onClick={() => alert("Withdraw flow here")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition-colors ${
              darkMode
                ? "bg-emerald-600/30 hover:bg-emerald-600/40 text-white"
                : "bg-emerald-500/20 hover:bg-emerald-500/30"
            }`}
          >
            <ArrowDownLeft className="w-4 h-4" /> Withdraw
          </button>
        </div>



      </div>

      {/* Recent Transactions */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className="font-bold text-lg">Recent Transactions</h2>
        </div>

        <div className="space-y-4 pb-64">
          {transactions.slice(0, 5).map((t) => {
            const isDeposit = t.type.includes("deposit");

            return (
              <div
                key={t.id}
                className={`flex items-center justify-between p-3 rounded-xl border ${
                  darkMode
                    ? "bg-gray-800 border-gray-700"
                    : "bg-white border-gray-50"
                }`}
              >
                <div className="flex items-center gap-3">
                  <div
                    className={`w-10 h-10 rounded-full flex items-center justify-center ${
                      isDeposit
                        ? "bg-emerald-100 text-emerald-600"
                        : "bg-red-100 text-red-600"
                    }`}
                  >
                    {isDeposit ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                  </div>

                  <div>
                    <p className={`font-semibold ${darkMode ? "text-gray-100" : "text-gray-800"}`}>
                      {t.title}
                    </p>
                    <p className="text-xs text-gray-400">{t.date}</p>
                  </div>
                </div>

                <span className={`font-bold text-sm ${
                  isDeposit
                    ? "text-emerald-600"
                    : darkMode
                    ? "text-gray-100"
                    : "text-gray-800"
                }`}>
                  {isDeposit ? "+" : "-"}
                  {formatAmount(t.amount)}
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* ---------- DEPOSIT FLOW MODAL ---------- */}
      {showDepositFlow && depositStep === "DepositScreen" && (
        <DepositScreen
          mainBalance={mainBalance}
          onBack={() => setShowDepositFlow(false)}
          onConfirm={handleDepositConfirm}
        />
      )}

      {showDepositFlow && depositStep === "ConfirmPaymentScreen" && (
        <ConfirmPaymentScreen
          amount={depositAmount}
          source={depositSource}
          destination="Nest Balance"
          fee={0}
          onBack={() => setDepositStep("DepositScreen")}
          onConfirm={handlePaymentProcessing}
        />
      )}

      {showDepositFlow && depositStep === "PaymentProcessingScreen" && (
        <PaymentProcessingScreen
          message="Processing your deposit..."
          onComplete={handlePaymentProcessing}
        />
      )}
    </div>
  );
}
